Bash(cd "D:\\_bootstrap\\slides-grab" && node --input-type=module -e "
import { chromium } from 'playwright';
import { join } from 'path';
import { pathToFileURL } from 'url';
import { getDomToSvgBundle } from './scripts/html2svg.js';

const slidesDir = join\(process.cwd\(\), 'decks/elevenlabs'\);
const slideFile = 'slide-01-title.html';
const bundlePath = getDomToSvgBundle\(\);

const browser = await chromium.launch\({ headless: true }\);
const page = await browser.newPage\(\);

// Load slide and run dom-to-svg
const slideUrl = pathToFileURL\(join\(slidesDir, slideFile\)\).href;
await page.goto\(slideUrl, { waitUntil: 'load' }\);
await page.evaluate\(async \(\) => { if \(document.fonts?.ready\) await document.fonts.ready; }\);

// Get raw dom-to-svg output \(before sanitization\)
await page.addScriptTag\({ path: bundlePath }\);
const rawSvg = await page.evaluate\(async \(\) => {
  const { elementToSVG, inlineResources } = window.__domToSvg;
  const svgDoc = elementToSVG\(document.body\);
  await inlineResources\(svgDoc.documentElement\);
  return new XMLSerializer\(\).serializeToString\(svgDoc\);
}\);

// Extract tspan textLength values and measure natural widths
const result = await page.evaluate\(\(svg\) => {
  const parser = new DOMParser\(\);
  const doc = parser.parseFromString\(svg, 'image/svg+xml'\);
  const canvas = document.createElement\('canvas'\);
  const ctx = canvas.getContext\('2d'\);
  const results = [];

  for \(const textEl of doc.querySelectorAll\('text'\)\) {
    const fontFamily = textEl.getAttribute\('font-family'\) || 'sans-serif';
    const fontSize = parseFloat\(textEl.getAttribute\('font-size'\)\) || 16;
    const fontWeight = textEl.getAttribute\('font-weight'\) || '400';
    const ls = textEl.getAttribute\('letter-spacing'\) || '0';
    const lsNum = \(ls === 'normal'\) ? 0 : parseFloat\(ls\) || 0;

    for \(const tspan of textEl.querySelectorAll\('tspan'\)\) {
      const text = tspan.textContent || '';
      const textLength = parseFloat\(tspan.getAttribute\('textLength'\)\);
      if \(!text.trim\(\) || !textLength\) continue;

      ctx.font = fontWeight + ' ' + fontSize + 'px ' + fontFamily;
      ctx.letterSpacing = lsNum + 'px';
      const naturalWidth = ctx.measureText\(text\).width;
      const delta = textLength - naturalWidth;
      const charCount = [...text].length;

      results.push\({
        text: text.slice\(0, 25\),
        fontSize,
        letterSpacing: lsNum,
        textLength: textLength.toFixed\(2\),
        naturalWidth: naturalWidth.toFixed\(2\),
        delta: delta.toFixed\(2\),
        charCount,
      }\);
    }
  }
  return results;
}, rawSvg\);

console.log\(JSON.stringify\(result, null, 2\)\);
await browser.close\(\);
" 2>&1)

